-- ============================================================
-- POI 4 - Đặc sản Huế 10 Thương
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (4, 'ko', '후에 10 트엉 특산물 전문점에 오신 것을 환영합니다. 이 가게는 특별한 그릇, 일반 그릇, 족발 분보와 양지 분보 등 진한 맛의 분보후에를 비롯한 후에 특산 요리를 전문으로 합니다. 후에식 반까인까록은 게살 완자, 가물치, 생선 머리, 족발과 함께 제공됩니다. 이 외에도 모듬 떡, 반남록, 차까이 등 다양한 음료도 준비되어 있습니다. 꼭 들러서 맛보세요.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (4, 'zh', '欢迎来到顺化特产10Thuong。本店专营顺化特色美食，包括浓郁的顺化牛肉粉，有特大碗、普通碗、猪蹄牛肉粉和牛腩牛肉粉。顺化鱼饼汤配有蟹肉丸、黑鱼、鱼头和猪蹄。此外还有什锦饼、叶包饼、肉卷以及多种饮品。欢迎光临品尝。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (4, 'ja', 'フエ名物料理店「10トゥオン」へようこそ。当店は、特盛・並盛・豚足入り・牛すね肉入りなど、濃厚な味わいのブンボーフエをはじめとするフエの名物料理を専門にしています。フエ風バインカインカーロックは、カニすり身、雷魚、魚の頭、豚足と一緒にお楽しみいただけます。その他にも盛り合わせ餅、バインナムロック、チャーカイなど、各種ドリンクもご用意しています。ぜひお立ち寄りください。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (4, 'th', 'ยินดีต้อนรับสู่ร้านอาหารพิเศษเว้ 10 เทือง ร้านนี้เชี่ยวชาญอาหารพิเศษของเว้ เช่น บุ๋นบ่อเว้รสเข้มข้น มีทั้งชามพิเศษ ชามธรรมดา บุ๋นบ่อขาหมู และบุ๋นบ่อเนื้อน่อง แกงบั๋นแกงปลาช่อนเว้กับลูกชิ้นปู ปลาช่อน หัวปลา และขาหมู นอกจากนี้ยังมีขนมรวมมิตร ขนมบั๋นนัมล็อก ชาก๊าย และเครื่องดื่มอีกมากมาย เชิญแวะมาลิ้มลองนะคะ', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (4, 'fr', 'Bienvenue chez Spécialités de Huế 10 Thương. Notre restaurant est spécialisé dans les spécialités culinaires de Huế, notamment le Bún Bò Huế au bouillon riche et savoureux, disponible en portion spéciale, portion normale, avec pied de porc ou jarret de bœuf. Le Bánh Canh Cá Lóc de Huế est servi avec des boulettes de crabe, du poisson-tête-de-serpent, de la tête de poisson et du pied de porc. Nous proposons également des gâteaux assortis, des bánh nậm lọc, des chả cây ainsi que de nombreuses boissons. Nous vous invitons à venir déguster nos plats.', NULL, 1, NOW());

-- ============================================================
-- POI 11 - Bánh khọt, bánh xèo
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (11, 'ko', '이곳은 바인콧과 바인쎄오를 판매하는 가게로, 베트남의 대표적인 음식을 저렴한 가격에 매우 맛있게 즐길 수 있습니다. 바인콧은 개당 5,000~10,000동, 바인쎄오는 개당 40,000~60,000동의 매우 저렴한 가격입니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (11, 'zh', '这是一家专卖越南煎饼（bánh khọt）和越式薄饼（bánh xèo）的店铺，这些都是越南的特色美食，价格实惠且味道极佳。小煎饼每个仅需5,000至10,000越南盾，大薄饼每个40,000至60,000越南盾，价格非常亲民。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (11, 'ja', 'こちらはバインコットとバインセオの専門店で、ベトナムを代表する料理をお手頃価格で美味しくお楽しみいただけます。バインコットは1個わずか5,000～10,000ドン、バインセオは1枚40,000～60,000ドンと大変リーズナブルです。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (11, 'th', 'ที่นี่คือร้านขายบั๋นค็อตและบั๋นแส้ว อาหารเด่นของเวียดนาม ราคาถูกแต่อร่อยมาก ในราคาเพียง 5,000 ถึง 10,000 ด่ง ต่อชิ้นบั๋นค็อต และ 40,000 ถึง 60,000 ด่ง ต่อชิ้นบั๋นแส้ว', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (11, 'fr', 'Voici un stand de bánh khọt et bánh xèo, des spécialités emblématiques du Vietnam, à prix très abordables et incroyablement délicieuses. Les bánh khọt ne coûtent que 5 000 à 10 000 VND pièce et les bánh xèo de 40 000 à 60 000 VND pièce.', NULL, 1, NOW());

-- ============================================================
-- POI 12 - Tiệm Bánh Family
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (12, 'ko', '패밀리 베이커리는 쭉쭉 늘어나는 치즈와 결합된 맛있고 향긋한 바게트로 유명합니다. 활기찬 아침 식사를 위한 이상적인 장소입니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (12, 'zh', 'Family面包店以香喷喷的面包搭配独特的拉丝芝士而闻名。这里是享用一顿元气满满早餐的理想驻足之地。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (12, 'ja', 'ファミリーベーカリーは、とろ〜り伸びるチーズと組み合わせた香ばしいパンで有名です。エネルギー満点の朝食にぴったりの立ち寄りスポットです。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (12, 'th', 'ร้านขนมปัง Family ขึ้นชื่อเรื่องขนมปังหอมอร่อยที่ผสมกับชีสยืดเส้นสุดพิเศษ ที่นี่คือจุดแวะพักในอุดมคติสำหรับมื้อเช้าที่เต็มไปด้วยพลัง', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (12, 'fr', 'La Boulangerie Family est réputée pour ses délicieux pains parfumés garnis de fromage filant, une combinaison unique et savoureuse. C''est l''arrêt idéal pour un petit-déjeuner plein d''énergie.', NULL, 1, NOW());

-- ============================================================
-- POI 13 - Bánh tráng nướng
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (13, 'ko', '반짱느엉(구운 라이스페이퍼)은 바삭한 라이스페이퍼 위에 메추리알, 튀긴 파, 향긋한 쇠고기 육포를 올린 인기 길거리 간식입니다. 숯불 위에서 직접 구워 독특한 훈연 향이 납니다. 가격은 15,000동부터로, 오후 간식으로 완벽합니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (13, 'zh', '烤米纸是深受喜爱的街头小吃，酥脆的米纸上铺满鹌鹑蛋、炸葱酥和香喷喷的牛肉干。直接在炭火上烤制，带有独特的烟熏风味。价格仅15,000越南盾起，是完美的下午茶点心。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (13, 'ja', 'バインチャンヌン（焼きライスペーパー）は、パリパリのライスペーパーにウズラの卵、揚げネギ、香ばしいビーフジャーキーをのせた人気のストリートフードです。炭火で直接焼くことで、独特のスモーキーな風味が生まれます。15,000ドンからと、午後のおやつにぴったりです。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (13, 'th', 'บั๋นตรังเนือง (แผ่นแป้งข้าวปิ้ง) เป็นอาหารว่างริมทางยอดนิยม แผ่นแป้งกรอบราดด้วยไข่นกกระทา หอมเจียว และเนื้อแห้งหอมฉุย ปิ้งบนถ่านร้อนโดยตรง ให้กลิ่นควันเป็นเอกลักษณ์ ราคาเริ่มต้นเพียง 15,000 ด่ง เหมาะสำหรับของว่างยามบ่าย', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (13, 'fr', 'Le bánh tráng nướng (galette de riz grillée) est un en-cas de rue très apprécié, composé d''une galette croustillante garnie d''œufs de caille, d''oignons frits et de bœuf séché parfumé. Grillée directement sur la braise, elle dégage une saveur fumée caractéristique. À partir de seulement 15 000 VND, c''est le goûter idéal pour l''après-midi.', NULL, 1, NOW());

-- ============================================================
-- POI 14 - Linh Bún Thái
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (14, 'ko', '린 분타이는 신선한 쌀국수에 새콤하고 매콤한 진한 육수를 곁들인 정통 태국 맛을 선사합니다. 신선한 새우, 돼지고기, 허브, 바삭한 땅콩이 어우러진 요리입니다. 분타이 한 그릇과 음료 한 잔에 25,000~35,000동이면 풍성하고 맛있는 한 끼를 즐길 수 있습니다. 그 외에도 매력적인 다양한 음료도 함께 판매하고 있습니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (14, 'zh', 'Linh泰式米粉带来正宗的泰国风味，新鲜的米粉配上酸辣浓郁的汤底。菜品融合了鲜虾、猪肉、香草和酥脆花生。一碗泰式米粉加一杯饮料仅需25,000至35,000越南盾，即可享用一顿丰盛美味的餐食。此外还搭配销售各种同样诱人的饮品。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (14, 'ja', 'リン・ブンタイは、新鮮な米麺に酸っぱ辛い濃厚スープを合わせた本格タイ料理の味わいをお届けします。新鮮なエビ、豚肉、ハーブ、カリカリのピーナッツが絶妙に組み合わさっています。ブンタイ1杯とドリンク1杯で25,000〜35,000ドンと、お手頃価格で大満足の一食です。その他にも魅力的な各種ドリンクも販売しています。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (14, 'th', 'ลินห์ บุ๋นไทย นำเสนอรสชาติไทยแท้ด้วยเส้นสดในน้ำซุปเปรี้ยวเผ็ดเข้มข้น ผสมผสานกุ้งสด เนื้อหมู ผักสมุนไพร และถั่วลิสงกรอบ ราคาเพียง 25,000-35,000 ด่ง ต่อชามบุ๋นไทยพร้อมเครื่องดื่ม 1 แก้ว อิ่มอร่อยเต็มอิ่ม นอกจากนี้ยังมีเครื่องดื่มหลากหลายชนิดที่น่าดึงดูดไม่แพ้กัน', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (14, 'fr', 'Linh Bún Thái vous offre des saveurs thaïlandaises authentiques avec des nouilles de riz fraîches dans un bouillon aigre-doux et épicé riche en saveurs. Le plat associe crevettes fraîches, porc, herbes aromatiques et cacahuètes croustillantes. Pour seulement 25 000 à 35 000 VND le bol de bún thaï avec une boisson, c''est un repas copieux et savoureux. Des boissons variées tout aussi attrayantes sont également proposées.', NULL, 1, NOW());

-- ============================================================
-- POI 15 - Cup Đẹp
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (15, 'ko', '컵뎹은 독특한 컵에 담긴 화려한 색상의 예쁜 음료 콘셉트로 눈길을 끕니다. 신선한 과일 차, 스무디부터 독특한 빙수까지 다양한 메뉴를 갖추고 있습니다. 모든 음료가 하나의 예술 작품으로, SNS 사진을 좋아하는 분들에게 완벽합니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (15, 'zh', 'Cup Đẹp以可爱的饮品概念脱颖而出，色彩缤纷的饮品盛放在独特的杯子中。菜单丰富多样，从新鲜水果茶、各式冰沙到独特的刨冰应有尽有。每一杯饮品都是一件艺术品，完美满足喜欢拍照打卡的你。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (15, 'ja', 'カップデップは、ユニークなカップに入ったカラフルで可愛いドリンクのコンセプトが際立つお店です。フレッシュフルーツティー、各種スムージーからユニークなビンスまで、多彩なメニューをご用意しています。すべてのドリンクがアート作品のようで、映え写真好きの方にぴったりです。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (15, 'th', 'Cup Đẹp โดดเด่นด้วยคอนเซ็ปต์เครื่องดื่มน่ารัก สีสันสดใส ในแก้วสุดเก๋ เมนูหลากหลายตั้งแต่ชาผลไม้สด สมูทตี้ ไปจนถึงบิงซูสุดพิเศษ ทุกแก้วคือผลงานศิลปะ เหมาะสำหรับสายถ่ายรูปโดยเฉพาะ', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (15, 'fr', 'Cup Đẹp se distingue par son concept de boissons mignonnes aux couleurs éclatantes, servies dans des gobelets originaux. Le menu est varié, allant des thés aux fruits frais, smoothies en tout genre, jusqu''aux bingsu uniques. Chaque boisson est une véritable œuvre d''art, parfaite pour les amateurs de photos Instagram.', NULL, 1, NOW());

-- ============================================================
-- POI 16 - Bò nướng Cambodia
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (16, 'ko', '캄보디아 소고기구이는 앙코르 사원의 나라 특유의 맛을 느낄 수 있는 요리로, 얇게 썬 소고기를 향신료에 재워 숯불 위에서 구워냅니다. 신선한 채소, 새콤한 오이 절임, 매콤한 소스와 함께 즐깁니다. 40,000~60,000동으로 베트남 한가운데서 캄보디아 미식을 경험할 수 있습니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (16, 'zh', '柬埔寨烤牛肉带来吴哥寺之国的独特风味，牛肉切薄片，用香料腌制后在炭火上烤制而成。搭配生菜、酸黄瓜和辛辣蘸酱一起享用。价格40,000至60,000越南盾，在越南的心脏地带体验柬埔寨美食。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (16, 'ja', 'カンボジア風焼き牛肉は、寺院の国ならではの独特な味わいが楽しめる一品です。薄くスライスした牛肉に香り豊かなスパイスを漬け込み、炭火で焼き上げます。生野菜、酸っぱいキュウリの漬物、辛いタレと一緒にいただきます。40,000〜60,000ドンで、ベトナムの中心でカンボジア料理を体験できます。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (16, 'th', 'เนื้อย่างกัมพูชานำเสนอรสชาติเฉพาะตัวจากดินแดนแห่งนครวัด เนื้อหั่นบาง หมักเครื่องเทศหอมฉุย ย่างบนถ่านร้อน ทานคู่กับผักสด แตงกวาดอง และน้ำจิ้มรสเผ็ดจัดจ้าน ราคา 40,000-60,000 ด่ง สัมผัสอาหารกัมพูชาใจกลางเวียดนาม', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (16, 'fr', 'Le bœuf grillé à la cambodgienne offre les saveurs caractéristiques du pays des temples, avec de fines tranches de bœuf marinées aux épices parfumées et grillées sur charbon de bois. Le plat est accompagné de crudités, de concombres marinés et d''une sauce piquante relevée. Pour 40 000 à 60 000 VND, vivez une expérience culinaire cambodgienne au cœur du Vietnam.', NULL, 1, NOW());

-- ============================================================
-- POI 17 - Mr Tea
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (17, 'ko', 'Mr Tea는 흑설탕 타피오카, 치즈 젤리, 에그 푸딩 등 다양한 토핑이 있는 밀크티의 천국입니다. 대만산 정통 찻잎으로 만들어지며, 당도는 취향에 따라 조절할 수 있습니다. 가격은 12,000~25,000동입니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (17, 'zh', 'Mr Tea是奶茶天堂，提供多种配料选择，从黑糖珍珠、芝士冻到鸡蛋布丁。饮品使用正宗台湾茶叶调制，甜度可根据个人口味自由调节。价格12,000至25,000越南盾。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (17, 'ja', 'Mr Teaは、黒糖タピオカ、チーズゼリー、エッグプリンなど多彩なトッピングが楽しめるミルクティーの楽園です。台湾産の本格茶葉を使用し、甘さはお好みに合わせて調整できます。価格は12,000〜25,000ドンです。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (17, 'th', 'Mr Tea คือสวรรค์ของชานม มีท็อปปิ้งหลากหลายตั้งแต่ไข่มุกน้ำตาลทรายแดง เยลลี่ชีส ไปจนถึงพุดดิ้งไข่ เครื่องดื่มชงจากชาไต้หวันแท้ ปรับระดับความหวานได้ตามใจชอบ ราคาเริ่มต้น 12,000-25,000 ด่ง', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (17, 'fr', 'Mr Tea est un paradis du thé au lait avec un large choix de garnitures : perles de tapioca au sucre brun, gelée au fromage ou pudding aux œufs. Les boissons sont préparées à partir de thé taïwanais authentique, avec un niveau de sucre ajustable selon vos préférences. Les prix vont de 12 000 à 25 000 VND.', NULL, 1, NOW());

-- ============================================================
-- POI 18 - Hủ tiếu trộn A.Hùng
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (18, 'ko', '아훙 비빔 후띠우는 새우, 고기, 바삭한 스프링롤, 향긋한 허브가 가득 담긴 드라이 비빔 후띠우로 유명합니다. 새콤달콤한 피시소스가 쫄깃한 면과 완벽하게 어우러집니다. 40,000~100,000동으로, 소박하지만 남부의 풍미 가득한 요리입니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (18, 'zh', 'A.Hùng干拌粿条以满满的虾、肉、酥脆春卷和香草的干拌粿条而闻名。酸甜鱼露与爽滑粿条完美融合。价格仅40,000至100,000越南盾，这道朴实的美食充满了南方风味。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (18, 'ja', 'アフン・フーティウは、エビ、肉、パリパリの揚げ春巻き、香草がたっぷり入った汁なし和えフーティウで有名です。甘酸っぱいヌクマムがもちもちの麺と絶妙にマッチします。40,000〜100,000ドンで、素朴ながらも南部の風味たっぷりの一品です。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (18, 'th', 'หูเตี๋ยวคลุกอาหุ่ง ขึ้นชื่อด้วยหูเตี๋ยวแห้งที่เต็มไปด้วยกุ้ง เนื้อหมู ปอเปี๊ยะทอดกรอบ และผักสมุนไพร น้ำปลาเปรี้ยวหวานเข้มข้นผสมผสานกับเส้นหูเตี๋ยวเหนียวนุ่มได้อย่างลงตัว ราคาเพียง 40,000 ถึง 100,000 ด่ง อาหารบ้านๆ แต่เต็มไปด้วยรสชาติแห่งภาคใต้', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (18, 'fr', 'Hủ Tiếu Trộn A.Hùng est célèbre pour ses nouilles sèches mélangées, généreusement garnies de crevettes, de viande, de nems croustillants et d''herbes fraîches. La sauce de poisson aigre-douce se marie parfaitement avec les nouilles moelleuses. Pour 40 000 à 100 000 VND, c''est un plat simple mais débordant de saveurs du Sud.', NULL, 1, NOW());

-- ============================================================
-- POI 19 - Khoai lang bong bóng
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (19, 'ko', '고구마 풍선 과자는 향긋한 자색 고구마에 녹아내리는 치즈와 바삭한 버블이 어우러진 독특한 디저트입니다. 노릇하게 튀겨 슈가파우더를 뿌려, 달콤함과 고소함이 완벽하게 조화를 이룹니다. 20,000~30,000동으로, 놓칠 수 없는 간식입니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (19, 'zh', '泡泡红薯是一道独特的甜品，由香喷喷的紫薯搭配融化的芝士和酥脆的泡泡制成。炸至金黄，撒上糖粉，在香甜和奶香之间达到完美平衡。价格仅20,000至30,000越南盾，是不容错过的小吃。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (19, 'ja', 'バブルさつまいもは、香り豊かな紫芋にとろけるチーズとサクサクのバブルを組み合わせたユニークなデザートです。こんがりと揚げて粉砂糖をまぶし、甘さとクリーミーさが絶妙にマッチしています。20,000〜30,000ドンで、見逃せないスナックです。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (19, 'th', 'มันหวานบอลลูนเป็นของหวานสุดพิเศษ ทำจากมันม่วงหอมหวาน ชีสเยิ้มละลาย และบอลลูนกรอบรัม ทอดจนเหลืองอร่าม โรยน้ำตาลผง ผสมผสานระหว่างความหวานและความมันได้อย่างลงตัว ราคาเพียง 20,000-30,000 ด่ง ของกินเล่นที่ห้ามพลาด', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (19, 'fr', 'La patate douce bulle est un dessert original composé de patate douce violette parfumée, de fromage fondant et de bulles croustillantes. Frite jusqu''à obtenir une belle couleur dorée et saupoudrée de sucre glace, elle offre un mariage parfait entre douceur sucrée et onctuosité. Pour seulement 20 000 à 30 000 VND, c''est un en-cas à ne pas manquer.', NULL, 1, NOW());

-- ============================================================
-- POI 20 - Đậu Hủ Thúi & Trà Sữa Cô Út
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (20, 'ko', '취두부 & 코웃 밀크티에 오신 것을 환영합니다. 이곳은 겉은 바삭하고 노릇하며, 속은 부드럽고 고소한 취두부 튀김으로 유명합니다. 새콤한 채소와 진한 소스를 곁들이면 거부할 수 없는 맛입니다. 또한 코웃 밀크티는 고소하고 적당히 달콤하며, 토핑이 풍부하여 느끼함을 잡아주고 상쾌함을 더해줍니다. 깨끗한 재료를 사용하고 즉석에서 조리하여 맛있고 안전하며 합리적인 가격을 보장합니다. 취두부 & 코웃 밀크티 – 향은 독특하지만, 한번 먹으면 중독됩니다. 오늘 꼭 방문해 보세요.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (20, 'zh', '欢迎来到臭豆腐&小姑奶茶。这里以炸得金黄酥脆、内里柔嫩细腻的臭豆腐闻名，搭配酸菜和浓郁酱汁，香气逼人，令人欲罢不能。此外还有小姑奶茶，奶香浓郁、甜度适中、配料丰富，完美解腻清爽。本店使用新鲜食材，现场制作，保证美味、安全、价格亲民。臭豆腐&小姑奶茶——闻起来独特，吃了就上瘾。欢迎今天就来品尝。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (20, 'ja', '臭豆腐＆コウット・ミルクティーへようこそ。こちらは外はカリカリで黄金色、中はふんわりクリーミーな臭豆腐の揚げ物で有名です。酸味のある野菜と濃厚なソースを添えると、たまらない美味しさです。また、コウット・ミルクティーはまろやかで程よい甘さ、トッピングも充実しており、口直しにぴったりです。新鮮な食材を使い、その場で調理し、美味しさ・安全性・お手頃価格をお約束します。臭豆腐＆コウット・ミルクティー – 香りは独特、食べたらやみつき。ぜひ今日お店にお越しください。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (20, 'th', 'ยินดีต้อนรับสู่เต้าหู้เหม็น & ชานมโกอุ๊ต ที่นี่ขึ้นชื่อเรื่องเต้าหู้เหม็นทอดกรอบนอกนุ่มใน เหลืองอร่ามด้านนอก เนียนนุ่มด้านใน ทานคู่กับผักเปรี้ยวและซอสเข้มข้น หอมอร่อยจนหยุดไม่ได้ นอกจากนี้ยังมีชานมโกอุ๊ต หอมมัน หวานพอดี ท็อปปิ้งเต็มแก้ว ช่วยตัดเลี่ยนได้อย่างดี ร้านใช้วัตถุดิบสะอาด ปรุงสดใหม่ รับประกันอร่อย ปลอดภัย ราคาเป็นกันเอง เต้าหู้เหม็น & ชานมโกอุ๊ต – กลิ่นเป็นเอกลักษณ์ ทานแล้วติดใจ เชิญแวะมาชิมได้เลยวันนี้', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (20, 'fr', 'Bienvenue chez Tofu Puant & Trà Sữa Cô Út. L''établissement est réputé pour son tofu fermenté frit, croustillant et doré à l''extérieur, tendre et onctueux à l''intérieur, servi avec des légumes marinés et une sauce savoureuse irrésistible. Le thé au lait Cô Út, crémeux et juste assez sucré avec de généreuses garnitures, accompagne parfaitement le tofu. Le restaurant utilise des ingrédients frais, préparés sur place, garantissant goût, sécurité et prix abordables. Tofu Puant & Trà Sữa Cô Út – une odeur unique, un goût addictif. Venez goûter dès aujourd''hui.', NULL, 1, NOW());

-- ============================================================
-- POI 21 - Cháo Lòng – Lòng Nhậu Vinh
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (21, 'ko', '차오롱 – 롱나우 빈에 오신 것을 환영합니다. 이 가게는 부드러운 쌀로 끓인 뜨끈한 내장죽과 자연스러운 단맛의 육수, 신선하고 깨끗하게 손질되어 냄새나 쓴맛이 없는 돼지 내장을 전문으로 합니다. 내장죽 외에도 순대, 간, 심장, 콩팥, 위 등 다양한 내장 안주가 있으며, 딱 알맞게 삶아 생강 액젓이나 진한 새우젓에 찍어 먹습니다. 든든한 아침, 간편한 점심, 저녁 친구들과의 술자리에 모두 적합합니다. 차오롱 – 롱나우 빈 – 뜨끈하고 진한 맛, 한번 먹으면 잊을 수 없습니다. 들어오셔서 바로 맛보세요.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (21, 'zh', '欢迎来到肠粥——龙脑酒菜Vinh。本店专营热腾腾的内脏粥，用软糯大米熬制，汤底清甜，搭配新鲜干净的猪内脏，精心处理，无腥无苦。除了内脏粥，店内还提供丰富的下酒内脏菜，包括香肠、猪肝、猪心、腰子、肚子等，煮至刚好熟透，蘸姜鱼露或浓郁虾酱食用。适合饱腹的早餐、简便的午餐或晚间与朋友小酌。肠粥——龙脑酒菜Vinh——热腾腾、味道浓、吃了就难忘。欢迎进店品尝。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (21, 'ja', 'チャオロン – ロンニャウ・ヴィンへようこそ。当店は、柔らかいお米で炊いたアツアツのモツ粥を専門としています。スープは自然な甘みがあり、新鮮で丁寧に下処理された豚モツは臭みや苦味がありません。モツ粥のほか、ソーセージ、レバー、ハツ、腎臓、胃袋など各種モツのおつまみも充実しており、ちょうど良い火加減で茹で上げ、生姜入りヌクマムや濃厚なマムトムでいただきます。お腹いっぱいの朝食、手軽なランチ、夜の友人との一杯にぴったりです。チャオロン – ロンニャウ・ヴィン – アツアツで味わい深く、一度食べたら忘れられません。ぜひお店にお越しください。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (21, 'th', 'ยินดีต้อนรับสู่ข้าวต้มเครื่องใน – เครื่องในกับแกล้มวินห์ ร้านเชี่ยวชาญข้าวต้มเครื่องในร้อนๆ หุงจากข้าวนุ่ม น้ำซุปหวานใส ผสมกับเครื่องในหมูสดสะอาด ผ่านการเตรียมอย่างพิถีพิถัน ไม่คาว ไม่ขม นอกจากข้าวต้มเครื่องในแล้ว ยังมีเครื่องในแกล้มครบทุกชนิด ทั้งไส้กรอก ตับ หัวใจ ไต กระเพาะ ต้มสุกพอดี จิ้มน้ำปลาขิงหรือกะปิเข้มข้น เหมาะสำหรับมื้อเช้าอิ่มท้อง มื้อเที่ยงรวดเร็ว หรือนั่งจิบเบียร์ยามค่ำกับเพื่อนฝูง ข้าวต้มเครื่องใน – เครื่องในกับแกล้มวินห์ – ร้อนๆ เข้มข้น ทานแล้วจำไม่ลืม เชิญเข้ามาลิ้มลองเลย', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (21, 'fr', 'Bienvenue chez Cháo Lòng – Lòng Nhậu Vinh. Le restaurant est spécialisé dans la bouillie de riz aux abats, servie bien chaude, préparée avec du riz tendre et un bouillon naturellement doux. Les abats de porc sont frais, soigneusement nettoyés, sans odeur ni amertume. En plus de la bouillie, le restaurant propose une variété d''abats pour accompagner l''apéritif : saucisses, foie, cœur, rognons et tripes, cuits à point et servis avec une sauce au poisson et gingembre ou une pâte de crevettes savoureuse. Idéal pour un petit-déjeuner copieux, un déjeuner rapide ou un apéritif entre amis le soir. Cháo Lòng – Lòng Nhậu Vinh – chaud, savoureux, inoubliable. Entrez et régalez-vous.', NULL, 1, NOW());

-- ============================================================
-- POI 22 - Heo Mọi Nướng Giả Cầy
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (22, 'ko', '헤오모이 느엉 자꺼이에 오신 것을 환영합니다. 이 가게는 갈랑갈, 발효 쌀, 레몬그라스의 향이 가득한 전통 자꺼이 양념으로 재운 신선한 멧돼지 요리를 전문으로 합니다. 숯불에 구운 멧돼지는 껍질이 가볍게 바삭하고, 살은 탄탄하며, 자연스러운 고소함이 있어 먹을수록 빠져듭니다. 자꺼이는 진한 양념에 은은한 매운맛이 있으며, 분이나 뜨끈한 밥과 함께 먹으면 친구들과의 모임이나 술자리에 아주 적합합니다. 당일 신선한 재료만 사용하며, 정성스럽게 조리하여 특유의 맛과 안전을 보장합니다. 헤오모이 느엉 자꺼이 – 시골의 진한 향, 한번 먹으면 영원히 기억에 남습니다. 들어오셔서 맛보세요.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (22, 'zh', '欢迎来到烤山猪假狗肉。本店专营新鲜山猪肉，以传统假狗肉配方腌制，散发着高良姜、酒糟和香茅的浓郁香气。山猪烤制于炭火之上，外皮轻薄酥脆，肉质紧实，自然鲜香，越吃越上瘾。假狗肉味浓微辣，搭配米粉或热米饭，非常适合朋友聚会或小酌。本店承诺每日使用新鲜食材，精心烹制，保证独特风味和食品安全。烤山猪假狗肉——浓浓乡土味，一吃永难忘。欢迎进店品尝。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (22, 'ja', 'ヘオモイ・ヌン・ザーカイへようこそ。当店はガランガル、発酵米、レモングラスの香りが効いた伝統的なザーカイ（犬肉風味）の味付けで漬け込んだ新鮮なイノシシ肉料理を専門としています。炭火で焼いたイノシシは皮が軽くパリッとし、肉は引き締まり、自然な旨味があり、食べるほどにクセになります。ザーカイは濃厚で程よい辛さがあり、ブンや熱々のご飯と一緒に食べると、友人との集まりや晩酌にぴったりです。毎日新鮮な食材を使用し、丁寧に調理して独特の風味と安全性をお約束します。ヘオモイ・ヌン・ザーカイ – 故郷の豊かな香り、一度食べたら一生忘れません。ぜひお店にお越しください。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (22, 'th', 'ยินดีต้อนรับสู่หมูป่าย่างยาก่าย ร้านเชี่ยวชาญหมูป่าสด หมักด้วยสูตรยาก่ายดั้งเดิม หอมกลิ่นข่า เหล้าหมัก และตะไคร้ หมูป่าย่างบนถ่านร้อน หนังกรอบเบาๆ เนื้อแน่น หอมมันตามธรรมชาติ ยิ่งทานยิ่งติดใจ ยาก่ายรสเข้มข้น เผ็ดเล็กน้อย ทานคู่กับบุ๋นหรือข้าวร้อน เหมาะสำหรับงานรวมเพื่อนหรือนั่งจิบเบียร์ยามค่ำ ร้านรับประกันวัตถุดิบสดใหม่ทุกวัน ปรุงอย่างพิถีพิถัน รับรองรสชาติเฉพาะตัวและความปลอดภัย หมูป่าย่างยาก่าย – หอมเข้มกลิ่นบ้านนา ทานครั้งเดียวจำไม่ลืม เชิญเข้ามาลิ้มลองเลย', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (22, 'fr', 'Bienvenue chez Heo Mọi Nướng Giả Cầy. Le restaurant est spécialisé dans le sanglier frais, mariné selon la recette traditionnelle du giả cầy, parfumé au galanga, au riz fermenté et à la citronnelle. Le sanglier est grillé sur charbon de bois : la peau est légèrement croustillante, la chair est ferme et naturellement savoureuse — plus on en mange, plus on en redemande. Le giả cầy, au goût prononcé et légèrement pimenté, se déguste avec des vermicelles ou du riz chaud, idéal pour les repas entre amis ou les soirées décontractées. Le restaurant s''engage à utiliser des ingrédients frais du jour, soigneusement préparés, garantissant saveur authentique et sécurité alimentaire. Heo Mọi Nướng Giả Cầy – les saveurs intenses de la campagne, un goût inoubliable. Entrez et régalez-vous.', NULL, 1, NOW());

-- ============================================================
-- POI 23 - Hủ Tiếu Sườn Sụn Liên
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (23, 'ko', '후띠우 쓴순 리엔에 오신 것을 환영합니다. 이 가게는 오래 삶아 부드러우면서도 특유의 오독오독한 식감을 유지하는 연골 갈비 후띠우로 유명합니다. 맑고 뼈에서 우러난 자연스러운 단맛의 육수에 적절한 간으로, 쫄깃한 면과 어우러져 완벽한 맛을 냅니다. 매 그릇이 뜨겁고 푸짐하게 준비되어 든든한 아침이나 낮의 가벼운 식사로 적합합니다. 매일 신선한 재료를 사용하며, 품질과 위생 안전을 보장합니다. 후띠우 쓴순 리엔 – 갈비는 바삭, 국물은 달콤, 한번 먹으면 중독됩니다. 들어오셔서 맛보세요.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (23, 'zh', '欢迎来到连记软骨排骨粿条。本店以精心炖煮的软骨排骨粿条闻名，排骨炖至软嫩却保留了标志性的脆弹口感，非常过瘾。汤底清澈，用骨头熬出自然甜味，调味恰到好处，搭配柔韧的粿条，口口满足。每碗粿条都热腾腾、分量十足，适合饱腹的早餐或日间轻食。本店承诺每日使用新鲜食材，确保品质和食品卫生安全。连记软骨排骨粿条——排骨脆弹、汤头清甜、吃了就上瘾。欢迎进店品尝。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (23, 'ja', 'フーティウ・スーンスン・リエンへようこそ。当店は、じっくり煮込んで柔らかくしながらも、コリコリとした特有の食感を残した軟骨付きスペアリブのフーティウで有名です。スープは澄んでおり、骨から出た自然な甘みがあり、味付けはちょうど良く、もちもちの麺と合わせて完璧な味わいです。どの一杯もアツアツでたっぷりで、お腹いっぱいの朝食や日中の軽食にぴったりです。毎日新鮮な食材を使用し、品質と衛生安全を保証しています。フーティウ・スーンスン・リエン – 軟骨はコリコリ、スープは甘い、食べたらやみつき。ぜひお店にお越しください。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (23, 'th', 'ยินดีต้อนรับสู่หูเตี๋ยวซี่โครงกระดูกอ่อนเลียน ร้านขึ้นชื่อด้วยหูเตี๋ยวซี่โครงกระดูกอ่อนที่ตุ๋นจนเนื้อนุ่มแต่ยังคงความกรุบกรอบเป็นเอกลักษณ์ ทานแล้วเพลินปาก น้ำซุปใส หวานจากกระดูก ปรุงรสพอดี ผสมกับเส้นหูเตี๋ยวเหนียวนุ่ม อร่อยครบรส ทุกชามเสิร์ฟร้อนๆ เต็มชาม เหมาะสำหรับมื้อเช้าอิ่มท้องหรือมื้อเบาระหว่างวัน ร้านรับประกันวัตถุดิบสดใหม่ทุกวัน มั่นใจในคุณภาพและความสะอาด หูเตี๋ยวซี่โครงกระดูกอ่อนเลียน – กระดูกกรอบ น้ำซุปหวาน ทานแล้วติดใจ เชิญเข้ามาลิ้มลองเลย', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (23, 'fr', 'Bienvenue chez Hủ Tiếu Sườn Sụn Liên. Le restaurant est renommé pour ses nouilles aux travers de porc cartilagineux, longuement mijotés jusqu''à être tendres tout en conservant leur texture croquante si caractéristique. Le bouillon est clair, naturellement sucré grâce aux os, parfaitement assaisonné, accompagnant des nouilles souples et savoureuses. Chaque bol est servi bien chaud et copieux, idéal pour un petit-déjeuner nourrissant ou un repas léger dans la journée. Le restaurant s''engage à utiliser des ingrédients frais quotidiennement, garantissant qualité et hygiène alimentaire. Hủ Tiếu Sườn Sụn Liên – des travers croquants, un bouillon doux, un goût addictif. Entrez et régalez-vous.', NULL, 1, NOW());

-- ============================================================
-- POI 24 - Khoai lang bong bóng (another branch)
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (24, 'ko', '고구마 풍선 과자는 향긋한 자색 고구마에 녹아내리는 치즈와 바삭한 버블이 어우러진 독특한 디저트입니다. 노릇하게 튀겨 슈가파우더를 뿌려, 달콤함과 고소함이 완벽하게 조화를 이룹니다. 20,000~30,000동으로, 놓칠 수 없는 간식입니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (24, 'zh', '泡泡红薯是一道独特的甜品，由香喷喷的紫薯搭配融化的芝士和酥脆的泡泡制成。炸至金黄，撒上糖粉，在香甜和奶香之间达到完美平衡。价格仅20,000至30,000越南盾，是不容错过的小吃。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (24, 'ja', 'バブルさつまいもは、香り豊かな紫芋にとろけるチーズとサクサクのバブルを組み合わせたユニークなデザートです。こんがりと揚げて粉砂糖をまぶし、甘さとクリーミーさが絶妙にマッチしています。20,000〜30,000ドンで、見逃せないスナックです。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (24, 'th', 'มันหวานบอลลูนเป็นของหวานสุดพิเศษ ทำจากมันม่วงหอมหวาน ชีสเยิ้มละลาย และบอลลูนกรอบรัม ทอดจนเหลืองอร่าม โรยน้ำตาลผง ผสมผสานระหว่างความหวานและความมันได้อย่างลงตัว ราคาเพียง 20,000-30,000 ด่ง ของกินเล่นที่ห้ามพลาด', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (24, 'fr', 'La patate douce bulle est un dessert original composé de patate douce violette parfumée, de fromage fondant et de bulles croustillantes. Frite jusqu''à obtenir une belle couleur dorée et saupoudrée de sucre glace, elle offre un mariage parfait entre douceur sucrée et onctuosité. Pour seulement 20 000 à 30 000 VND, c''est un en-cas à ne pas manquer.', NULL, 1, NOW());

-- ============================================================
-- POI 25 - Chén trứng nướng
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (25, 'ko', '뚝배기 계란구이는 신선한 계란, 치즈, 소시지, 채소를 뜨거운 뚝배기에 구운 매력적인 한국식 요리입니다. 녹아내리는 치즈가 부드러운 계란과 어우러져 거부할 수 없는 고소함을 선사합니다. 30,000~50,000동으로, 맛있는 한국식 간식입니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (25, 'zh', '砂锅烤蛋是一道诱人的韩式料理，将新鲜鸡蛋、芝士、香肠和蔬菜放在热腾腾的砂锅中烤制而成。融化的芝士与嫩滑的鸡蛋交融，带来令人难以抗拒的醇厚口感。价格30,000至50,000越南盾，美味的韩式小食。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (25, 'ja', 'チェン・チュン・ヌンは、新鮮な卵、チーズ、ソーセージ、野菜を熱い陶器の器で焼き上げた魅力的な韓国風料理です。とろけるチーズがふわふわの卵と絡み合い、たまらないコクを生み出します。30,000〜50,000ドンで、美味しい韓国風スナックです。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (25, 'th', 'ไข่อบถ้วยเป็นอาหารเกาหลีน่าดึงดูด ทำจากไข่ไก่สด ชีส ไส้กรอก และผัก อบในถ้วยดินเผาร้อนๆ ชีสละลายเข้ากับไข่นุ่มเนียน ให้รสมันเข้มข้นจนหยุดไม่ได้ ราคา 30,000-50,000 ด่ง ของว่างสไตล์เกาหลีแสนอร่อย', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (25, 'fr', 'L''œuf grillé en coupelle est un plat coréen attrayant composé d''œufs frais, de fromage, de saucisses et de légumes, cuit dans une coupelle en terre cuite brûlante. Le fromage fondu se mêle à l''œuf moelleux pour un résultat onctueux et irrésistible. Pour 30 000 à 50 000 VND, c''est un délicieux en-cas à la coréenne.', NULL, 1, NOW());

-- ============================================================
-- POI 26 - Xiên Nướng Bin Bo
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (26, 'ko', '시엔느엉 빈보에 오신 것을 환영합니다. 이 가게는 진한 양념에 재워 현장에서 숯불로 구워 멀리서부터 군침이 도는 꼬치구이를 전문으로 합니다. 고기, 해산물, 튀긴 볼, 채소 등 다양한 메뉴가 있으며, 모든 꼬치가 딱 알맞게 구워져 자연스러운 단맛을 간직합니다. 특제 소스에 찍어 먹으면 매콤하고 짭짤하고 달콤한 조화가 먹을수록 중독됩니다. 오후 간식, 친구 모임, 저녁 술자리에 딱 좋습니다. 시엔느엉 빈보 – 뜨겁고 맛있고, 어느 꼬치나 품질 보장. 꼭 들러서 맛보세요.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (26, 'zh', '欢迎来到Bin Bo烤串。本店专营炭火烤串，用浓郁酱料腌制，现场烧烤，远远就能闻到香味。菜单丰富多样，有肉类、海鲜、炸丸子和蔬菜，每串都烤至恰到好处，保留食材的天然甜味。搭配特制蘸酱，微辣、咸甜平衡，越吃越上瘾。适合下午零食、朋友聚会或晚间小酌。Bin Bo烤串——热腾腾、香喷喷，串串都是好品质。欢迎光临品尝。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (26, 'ja', 'シエンヌン・ビンボーへようこそ。当店は、しっかり味付けした串を炭火で焼き上げ、遠くからでもお腹が空く香りが漂う串焼き専門店です。肉、シーフード、揚げ団子、野菜など多彩なメニューがあり、どの串もちょうど良い焼き加減で素材の甘みを活かしています。特製のピリ辛で甘じょっぱいタレにつけて食べると、やみつきになること間違いなしです。午後のおやつ、友人との集まり、夜の一杯にぴったりです。シエンヌン・ビンボー – アツアツで美味しい、どの串も品質保証。ぜひお越しください。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (26, 'th', 'ยินดีต้อนรับสู่เซียนเนือง บินโบ ร้านเชี่ยวชาญเสียบย่างถ่านร้อน หมักเครื่องเทศเข้มข้น ย่างสดใหม่ที่ร้าน กลิ่นหอมลอยมาแต่ไกลก็หิวแล้ว เมนูหลากหลายทั้งเนื้อ อาหารทะเล ลูกชิ้นทอด และผัก ทุกไม้ย่างสุกพอดี เก็บรสหวานธรรมชาติไว้ครบ ทานคู่น้ำจิ้มสูตรพิเศษ เผ็ดๆ เค็มๆ หวานๆ กลมกล่อม ยิ่งทานยิ่งติด เหมาะสำหรับของว่างยามบ่าย สังสรรค์เพื่อนฝูง หรือนั่งจิบเบียร์ยามค่ำ เซียนเนือง บินโบ – ร้อนๆ หอมๆ ทุกไม้คุณภาพ เชิญแวะมาลิ้มลองเลย', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (26, 'fr', 'Bienvenue chez Xiên Nướng Bin Bo. Le restaurant est spécialisé dans les brochettes grillées au charbon de bois, marinées dans une sauce savoureuse et grillées sur place — l''arôme attire dès les premiers pas. Le menu varié propose viandes, fruits de mer, boulettes frites et légumes, chaque brochette est grillée à point pour préserver la douceur naturelle des ingrédients. Accompagnées d''une sauce maison épicée, salée et sucrée en parfait équilibre, elles sont tout simplement addictives. Idéal pour un goûter, une soirée entre amis ou un apéritif. Xiên Nướng Bin Bo – chaud, savoureux, chaque brochette est un gage de qualité. Venez déguster.', NULL, 1, NOW());

-- ============================================================
-- POI 27 - Hủ Tiếu Nam Vang Phú Quý
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (27, 'ko', '후띠우 남방 푸꿔이에 오신 것을 환영합니다. 이 가게는 정통 남방식 후띠우를 전문으로 하며, 뼈를 오래 우려낸 맑고 은은하게 달콤한 향긋한 육수가 특징입니다. 매 그릇에 새우, 고기, 간, 메추리알, 소장이 풍성하게 담기며, 쫄깃한 면과 조화로운 맛을 이룹니다. 국물 또는 비빔으로 선택 가능하며, 진한 소스와 신선한 채소를 곁들여 먹습니다. 아침, 점심 또는 가벼운 식사에 적합합니다. 후띠우 남방 푸꿔이 – 전통의 완벽한 맛, 먹으면 보배를 느낍니다. 들어오셔서 맛보세요.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (27, 'zh', '欢迎来到金边粿条富贵。本店专营正宗金边粿条，汤底清澈，骨头长时间熬制出自然甜味，带有淡淡的独特香气。每碗粿条配料丰富，有虾、肉、猪肝、鹌鹑蛋和小肠，搭配柔韧的粿条，口味和谐。可选汤粉或干拌，配以浓郁酱汁和新鲜蔬菜。适合早餐、午餐或日间轻食。金边粿条富贵——传统圆满好滋味，吃了就觉得"富贵"。欢迎进店品尝。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (27, 'ja', 'フーティウ・ナムヴァン・フークイへようこそ。当店は、骨をじっくり煮込んだ澄んだスープに自然な甘みとほのかな独特の香りが漂う、本格プノンペン風フーティウを専門としています。各一杯にエビ、肉、レバー、うずらの卵、小腸がたっぷり入り、もちもちの麺と調和のとれた味わいです。スープ入りまたは汁なしでお選びいただけ、濃厚なソースと新鮮な野菜を添えてどうぞ。朝食、昼食、または日中の軽食にぴったりです。フーティウ・ナムヴァン・フークイ – 伝統の円やかな味わい、食べれば幸せを感じます。ぜひお店にお越しください。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (27, 'th', 'ยินดีต้อนรับสู่หูเตี๋ยวน่ำวาง ฟู้กวี้ ร้านเชี่ยวชาญหูเตี๋ยวน่ำวางรสชาติดั้งเดิม น้ำซุปใส หวานจากกระดูกที่เคี่ยวนาน หอมอ่อนๆ เป็นเอกลักษณ์ ทุกชามเต็มไปด้วยกุ้ง เนื้อหมู ตับ ไข่นกกระทา และไส้หมู ผสมกับเส้นหูเตี๋ยวเหนียวนุ่ม รสชาติกลมกล่อม เลือกได้ทั้งแบบน้ำและแบบแห้ง ทานคู่กับซอสเข้มข้นและผักสด เหมาะสำหรับมื้อเช้า มื้อเที่ยง หรือมื้อเบาระหว่างวัน หูเตี๋ยวน่ำวาง ฟู้กวี้ – รสชาติดั้งเดิมครบถ้วน ทานแล้วรู้สึกมีค่า เชิญเข้ามาลิ้มลองเลย', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (27, 'fr', 'Bienvenue chez Hủ Tiếu Nam Vang Phú Quý. Le restaurant est spécialisé dans les authentiques nouilles phnom-penhoises, avec un bouillon clair, naturellement sucré grâce aux os longuement mijotés, et un parfum subtil caractéristique. Chaque bol est généreusement garni de crevettes, de viande, de foie, d''œufs de caille et d''intestins, accompagnés de nouilles souples pour un goût harmonieux. Disponible en version soupe ou sèche, servi avec une sauce riche et des légumes frais. Idéal pour le petit-déjeuner, le déjeuner ou un repas léger. Hủ Tiếu Nam Vang Phú Quý – la saveur traditionnelle parfaitement ronde. Entrez et régalez-vous.', NULL, 1, NOW());

-- ============================================================
-- POI 28 - Lẩu Bò Hoàng Thu
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (28, 'ko', '라우보 호앙투에 오신 것을 환영합니다. 이 가게는 소뼈로 우려낸 자연스러운 단맛에 레몬그라스, 고추, 특제 향신료의 향이 가득한 신선한 소고기 요리와 소고기 전골을 전문으로 합니다. 송아지고기, 타타키 소고기, 힘줄, 양, 꼬리 등 다양한 소고기 부위를 볶음, 찜, 샤부샤부, 구이 등 여러 방법으로 조리합니다. 전골에 신선한 채소, 면 또는 분을 곁들이면 가족 모임, 친구들과의 저녁, 술자리에 아주 적합합니다. 매일 신선한 재료를 사용하며, 정성스럽게 조리하여 맛과 품질을 보장합니다. 라우보 호앙투 – 진한 소고기 맛, 속이 따뜻해지고, 한번 먹으면 중독됩니다. 들어오셔서 맛보세요.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (28, 'zh', '欢迎来到黄秋牛肉火锅。本店专营新鲜牛肉和浓郁牛肉火锅，汤底用牛骨熬制，自然鲜甜，散发着香茅、辣椒和特色香料的独特香气。菜单丰富多样，有嫩牛肉、生牛肉、牛筋、牛百叶、牛尾等，烹饪方式包括炒、蒸、涮和烤。火锅搭配新鲜蔬菜、面条或米粉，非常适合家庭聚餐、朋友相约或夜间小酌。本店承诺每日使用新鲜食材，精心烹制，确保美味和品质。黄秋牛肉火锅——牛肉味浓、暖心暖胃、吃了就上瘾。欢迎进店品尝。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (28, 'ja', 'ラウボー・ホアントゥーへようこそ。当店は新鮮な牛肉料理と濃厚な牛肉鍋を専門としています。牛骨からじっくり煮出した自然な甘みのスープに、レモングラス、唐辛子、特製スパイスの香りが漂います。子牛肉、タタキ、牛すじ、センマイ、テールなど多彩な牛肉を、炒め、蒸し、しゃぶしゃぶ、焼きなど様々な調理法でご提供します。鍋には新鮮な野菜、麺やブンを合わせて、家族の集まり、友人との夕食、晩酌にぴったりです。毎日新鮮な食材を使用し、丁寧に調理して味と品質をお約束します。ラウボー・ホアントゥー – 濃厚な牛肉の旨味、体の芯から温まる、食べたらやみつき。ぜひお店にお越しください。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (28, 'th', 'ยินดีต้อนรับสู่หม้อไฟเนื้อวัวโห่างทู ร้านเชี่ยวชาญเนื้อวัวสดและหม้อไฟเนื้อวัวรสเข้มข้น น้ำซุปต้มจากกระดูกวัว หวานตามธรรมชาติ หอมกลิ่นตะไคร้ พริก และเครื่องเทศพิเศษ เมนูหลากหลายตั้งแต่เนื้อลูกวัว เนื้อสด เอ็น ผ้าขี้ริ้ว หางวัว ปรุงได้หลายแบบทั้งผัด นึ่ง จุ่ม และย่าง หม้อไฟทานคู่กับผักสด เส้นบะหมี่หรือเส้นบุ๋น เหมาะสำหรับงานรวมครอบครัว สังสรรค์เพื่อนฝูง หรือนั่งจิบเบียร์ยามค่ำ ร้านรับประกันวัตถุดิบสดใหม่ทุกวัน ปรุงอย่างพิถีพิถัน รับรองรสชาติและคุณภาพ หม้อไฟเนื้อวัวโห่างทู – เข้มข้นรสเนื้อ อุ่นท้อง ทานแล้วติดใจ เชิญเข้ามาลิ้มลองเลย', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (28, 'fr', 'Bienvenue chez Lẩu Bò Hoàng Thu. Le restaurant est spécialisé dans le bœuf frais et la fondue de bœuf savoureuse, avec un bouillon mijoté à partir d''os de bœuf, naturellement doux, parfumé à la citronnelle, au piment et aux épices caractéristiques. Le menu varié propose du veau, du bœuf cru, du tendon, de la panse, de la queue de bœuf, préparés de multiples façons : sautés, à la vapeur, en fondue ou grillés. La fondue s''accompagne de légumes frais, de nouilles ou de vermicelles, idéale pour les repas en famille, entre amis ou les soirées décontractées. Le restaurant s''engage à utiliser des ingrédients frais quotidiennement, garantissant saveur et qualité. Lẩu Bò Hoàng Thu – riche en saveurs bovines, réconfortant et addictif. Entrez et régalez-vous.', NULL, 1, NOW());

-- ============================================================
-- POI 29 - Lẩu Bò Cô Thảo
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (29, 'ko', '라우보 코타오에 오신 것을 환영합니다. 이 가게는 소뼈로 우려낸 자연스러운 단맛과 전통적인 풍미가 진한 소고기 전골과 신선한 소고기 요리를 전문으로 합니다. 모듬 소고기 전골, 발효쌀소스 샤부샤부 전골, 소꼬리 전골부터 소고기 구이, 볶음, 찜, 타타키 레몬까지 다양한 메뉴가 있습니다. 소고기와 내장은 엄선하여 깨끗하게 손질되어 쫄깃하고 달콤하며 냄새가 없습니다. 전골에 신선한 채소, 면, 쌀국수 또는 토란을 곁들이면 가족 모임이나 친구들과의 저녁 술자리에 아주 적합합니다. 라우보 코타오 – 뜨끈한 전골, 완벽한 맛, 먹으면 속이 시원합니다. 들어오셔서 맛보세요.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (29, 'zh', '欢迎来到草姐牛肉火锅。本店专营牛肉火锅和各种新鲜牛肉菜品，汤底用牛骨熬制，自然鲜甜，传统风味浓郁。菜单丰富，从什锦牛肉火锅、酸酒糟涮牛肉锅、牛尾锅，到烤牛肉、炒牛肉、蒸牛肉和柠檬生牛肉应有尽有。牛肉和内脏经过精选，处理干净，保持脆嫩、鲜甜且无异味。火锅搭配新鲜蔬菜、面条、河粉或芋头，非常适合家庭聚餐或朋友夜间小酌。草姐牛肉火锅——热腾腾一锅、滋味圆满、吃了就过瘾。欢迎进店品尝。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (29, 'ja', 'ラウボー・コータオへようこそ。当店は牛骨からじっくり煮出した自然な甘みと伝統の深い味わいが特徴の牛肉鍋と新鮮な牛肉料理を専門としています。盛り合わせ牛肉鍋、発酵米ソースのしゃぶしゃぶ鍋、テール鍋から、焼き牛肉、炒め牛肉、蒸し牛肉、レモン〆のタタキまで豊富なメニューをご用意しています。牛肉と内臓は厳選して丁寧に下処理し、コリコリとした食感と甘みを保ち、臭みがありません。鍋には新鮮な野菜、麺、フォーやタロイモを合わせて、家族の集まりや友人との晩酌にぴったりです。ラウボー・コータオ – アツアツの鍋、完璧な味わい、食べれば大満足。ぜひお店にお越しください。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (29, 'th', 'ยินดีต้อนรับสู่หม้อไฟเนื้อวัวโกถ่าว ร้านเชี่ยวชาญหม้อไฟเนื้อวัวและเนื้อวัวสดหลากหลายเมนู น้ำซุปต้มจากกระดูกวัว หวานตามธรรมชาติ เข้มข้นรสชาติดั้งเดิม เมนูหลากหลายตั้งแต่หม้อไฟเนื้อรวมมิตร หม้อไฟเนื้อจุ่มน้ำส้มหมัก หม้อไฟหางวัว ไปจนถึงเนื้อย่าง เนื้อผัด เนื้อนึ่ง และเนื้อสดมะนาว เนื้อวัวและเครื่องในคัดสรรอย่างดี ทำความสะอาดพิถีพิถัน คงความกรุบกรอบ หวาน และไม่คาว หม้อไฟทานคู่กับผักสด เส้นบะหมี่ เส้นเฝอ หรือเผือก เหมาะสำหรับงานรวมครอบครัวหรือสังสรรค์เพื่อนยามค่ำ หม้อไฟเนื้อวัวโกถ่าว – หม้อร้อนๆ รสชาติครบ ทานแล้วสะใจ เชิญเข้ามาลิ้มลองเลย', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (29, 'fr', 'Bienvenue chez Lẩu Bò Cô Thảo. Le restaurant est spécialisé dans la fondue de bœuf et les plats de bœuf frais, avec un bouillon mijoté à partir d''os de bœuf, naturellement doux et riche en saveurs traditionnelles. Le menu varié comprend la fondue de bœuf assortie, la fondue au riz fermenté, la fondue de queue de bœuf, ainsi que du bœuf grillé, sauté, à la vapeur et en tartare au citron. Le bœuf et les abats sont soigneusement sélectionnés et nettoyés, conservant leur texture croquante, leur douceur naturelle et sans odeur désagréable. La fondue s''accompagne de légumes frais, de nouilles, de phở ou de taro, parfaite pour les repas en famille ou les soirées entre amis. Lẩu Bò Cô Thảo – une marmite bouillante, des saveurs parfaites, une satisfaction garantie. Entrez et régalez-vous.', NULL, 1, NOW());

-- ============================================================
-- POI 30 - Ốc Hồng
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (30, 'ko', '옥홍에 오신 것을 환영합니다. 다양한 종류의 신선한 조개와 고둥을 진한 양념으로 조리하여, 서민적이지만 품질은 최고인 술안주 전문점입니다. 버터 마늘 볶음, 타마린드 볶음, 레몬그라스 고추 볶음부터 찐 조개, 구운 가리비, 소금 구이 게 다리까지 – 모든 요리가 향긋하고, 테이블에 오르면 바로 먹고 싶어집니다. 매일 신선한 재료를 사용하며, 적절한 양념과 특별한 소스가 옥홍만의 맛을 만들어냅니다. 시원한 공간, 빠른 서비스, 합리적인 가격 – 친구 모임이나 퇴근 후 술자리에 이상적입니다. 옥홍 – 조개부터 맛있고, 한 번 먹으면 첫 맛부터 중독됩니다!', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (30, 'zh', '欢迎来到红螺。这里汇集各类新鲜螺蛳贝类，调味浓郁，是正宗的平民美食但品质一流。从黄油蒜蓉炒螺、酸角炒螺、香茅辣椒炒螺，到蒸蛤蜊、烤扇贝、椒盐蟹钳——每道菜都香气扑鼻，上桌就让人迫不及待。食材每天保持新鲜，调味恰到好处，特制蘸酱成就了红螺独有的风味。环境通风舒适，上菜快速，价格实惠——朋友聚会或下班后小酌的理想之选。红螺——从螺开始就好吃，第一口就上瘾！', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (30, 'ja', 'オックホンへようこそ。新鮮な貝や巻貝を濃厚な味付けで調理した、庶民的ながらも品質抜群の居酒屋です。バターガーリック炒め、タマリンド炒め、レモングラスと唐辛子の炒めから、蒸しアサリ、焼きホタテ、塩焼きカニ爪まで – どの料理も香り高く、テーブルに並んだ瞬間に食べたくなります。毎日新鮮な食材を使い、絶妙な味付けと特製ソースがオックホンならではの味わいを生み出します。開放的な空間、素早いサービス、リーズナブルな価格 – 友人との集まりや仕事帰りの一杯に最適です。オックホン – 貝から美味しい、初めての一口からやみつきに！', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (30, 'th', 'ยินดีต้อนรับสู่หอยแดง ที่รวมหอยสดนานาชนิด ปรุงรสเข้มข้น เป็นร้านกับแกล้มสไตล์บ้านๆ แต่คุณภาพไม่ต้องพูดถึง ตั้งแต่หอยผัดเนยกระเทียม หอยผัดมะขาม หอยผัดตะไคร้พริก ไปจนถึงหอยนึ่ง หอยเชลล์ย่าง ก้ามปูคั่วเกลือ – ทุกจานหอมฉุย พอขึ้นโต๊ะก็อยากทานทันที วัตถุดิบสดใหม่ทุกวัน ปรุงรสพอดี น้ำจิ้มเข้มข้นสร้างรสชาติเฉพาะตัวของหอยแดง บรรยากาศโปร่งสบาย เสิร์ฟเร็ว ราคาเป็นกันเอง – เหมาะสำหรับสังสรรค์เพื่อนฝูงหรือนั่งชิลล์หลังเลิกงาน หอยแดง – อร่อยตั้งแต่ตัวหอย ติดใจตั้งแต่คำแรก!', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (30, 'fr', 'Bienvenue chez Ốc Hồng, le rendez-vous de tous les amateurs de fruits de mer frais, préparés avec des assaisonnements savoureux — un restaurant populaire mais d''une qualité irréprochable. Des escargots sautés au beurre et à l''ail, au tamarin, à la citronnelle et au piment, en passant par les palourdes à la vapeur, les coquilles Saint-Jacques grillées et les pinces de crabe au sel — chaque plat est parfumé et donne envie de se servir dès qu''il arrive sur la table. Les ingrédients sont frais chaque jour, l''assaisonnement est parfaitement dosé et la sauce maison fait toute la singularité d''Ốc Hồng. L''espace est aéré, le service rapide et les prix raisonnables — idéal pour les retrouvailles entre amis ou l''apéritif après le travail. Ốc Hồng – délicieux dès le premier coquillage, addictif dès la première bouchée !', NULL, 1, NOW());

-- ============================================================
-- POI 31 - Bò lụi sả – Chợ Hồ Thị Kỷ
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (31, 'ko', '보루이사 – 호티끼 시장은 레몬그라스의 독특한 향과 소고기의 자연스러운 달콤하고 부드러운 맛으로 식객들을 사로잡는 유명한 길거리 음식입니다. 소고기에 진한 양념을 하고 레몬그라스 줄기에 감아 숯불 위에서 구워, 겉은 살짝 그을리고 속은 촉촉하고 향긋합니다. 생채소, 빵 또는 분과 함께 청고추 소금이나 특제 소스에 찍어 먹으면 진하고 은은하게 매운 맛이 입맛을 돋웁니다. 보루이사는 간식, 친구 모임, 또는 호티끼의 활기찬 야시장 탐방에 이상적인 선택입니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (31, 'zh', '香茅牛肉串——胡氏纪市场，是一道著名的街头美食，以香茅的独特芬芳和牛肉的自然鲜甜嫩滑吸引着众多食客。牛肉用浓郁酱料腌制后，裹在香茅杆上在炭火上烤制，外层微微焦香，内里鲜嫩多汁、香气四溢。通常搭配生菜、面包或米粉，蘸青椒盐或特制酱汁食用，味道浓郁、微辣，非常开胃。香茅牛肉串是零食小吃、朋友聚会或探索胡氏纪热闹夜市的理想选择。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (31, 'ja', 'ボールイサー – ホーティーキー市場は、レモングラスの独特な香りと牛肉の自然な甘みと柔らかさで食通を魅了する有名なストリートフードです。牛肉にしっかりと味付けし、レモングラスの茎に巻いて炭火で焼き上げます。外側は軽く焦げ、中はジューシーで香り豊かです。生野菜、パンやブンと一緒に、青唐辛子塩や特製ソースにつけて食べると、濃厚でほんのり辛い味わいがクセになります。ボールイサーは、おやつ、友人との集まり、ホーティーキーの活気あるナイトマーケット探索にぴったりです。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (31, 'th', 'เนื้อย่างตะไคร้ – ตลาดโห่ทีกี่ เป็นอาหารริมทางชื่อดังที่ดึงดูดนักชิมด้วยกลิ่นหอมเฉพาะตัวของตะไคร้และรสหวานนุ่มตามธรรมชาติของเนื้อวัว เนื้อหมักเครื่องเทศเข้มข้น พันรอบก้านตะไคร้แล้วย่างบนถ่านร้อน ด้านนอกไหม้เล็กน้อย ด้านในฉ่ำนุ่มหอมฟุ้ง มักทานคู่กับผักสด ขนมปัง หรือบุ๋น จิ้มเกลือพริกเขียวหรือน้ำจิ้มสูตรพิเศษ รสเข้มข้น เผ็ดเล็กน้อย เหมาะสำหรับทานเล่น สังสรรค์เพื่อนฝูง หรือสำรวจตลาดกลางคืนสุดคึกคักของโห่ทีกี่', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (31, 'fr', 'Le bœuf grillé à la citronnelle du marché Hồ Thị Kỷ est un plat de rue célèbre qui séduit par le parfum unique de la citronnelle et la douceur naturelle de la viande de bœuf. Le bœuf est mariné dans des épices savoureuses, enroulé autour d''une tige de citronnelle puis grillé sur charbon de bois, créant une surface légèrement caramélisée et un intérieur tendre et parfumé. Il se déguste avec des crudités, du pain ou des vermicelles, trempé dans du sel au piment vert ou une sauce spéciale, offrant des saveurs riches et légèrement piquantes très appétissantes. Le bœuf à la citronnelle est le choix idéal pour un en-cas, une sortie entre amis ou pour explorer l''animation du marché nocturne de Hồ Thị Kỷ.', NULL, 1, NOW());

-- ============================================================
-- POI 32 - Cơm Chay Hoa Sen
-- ============================================================

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (32, 'ko', '호아센 채식 식당은 다양한 메뉴, 편한 맛, 합리적인 가격으로 많은 식객에게 친숙한 서민 채식 식당입니다. 정식, 후띠우, 분후에, 채식 쌀국수, 분리에우, 볶음면, 볶음밥 등 다양한 인기 채식 메뉴를 제공하여, 간편한 점심이나 가벼운 저녁 식사에 적합합니다. 모든 음식은 담백하게 조리되고, 적절한 양념으로 영양 균형과 건강에 중점을 두고 있습니다. 소박하고 친근한 분위기로, 정기적인 채식주의자는 물론 건강하고 경제적인 채식 식사로 변화를 주고 싶은 분들에게도 적합합니다.', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (32, 'zh', '莲花素食餐厅是一家平价素食餐厅，以丰富的菜单、易于接受的口味和实惠的价格深受众多食客喜爱。餐厅供应多种受欢迎的素食菜品，如素食套餐、粿条、顺化米粉、素河粉、螃蟹米粉、炒面、炒饭等，适合快捷午餐或轻松晚餐。所有菜品烹饪清淡，调味适中，注重营养均衡和健康。环境简朴亲切，既适合经常吃素的人，也适合想用健康经济的素食餐来换换口味的朋友。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (32, 'ja', 'ホアセン精進料理店は、豊富なメニュー、食べやすい味付け、お手頃な価格で多くの方に親しまれている庶民的な精進料理店です。定食、フーティウ、ブンフエ、精進フォー、ブンリエウ、焼きそば、チャーハンなど人気の精進メニューを多数取り揃えており、手軽なランチや軽めの夕食にぴったりです。すべての料理はあっさりと調理され、適切な味付けで栄養バランスと健康に配慮しています。シンプルで親しみやすい雰囲気で、日常的にベジタリアンの方はもちろん、ヘルシーで経済的な精進料理で気分転換したい方にもおすすめです。', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (32, 'th', 'ร้านอาหารเจโห่าเซน เป็นร้านอาหารเจราคาประหยัดที่คุ้นเคยกับนักชิมหลายคน ด้วยเมนูหลากหลาย รสชาติทานง่าย และราคาเป็นกันเอง ร้านเสิร์ฟอาหารเจยอดนิยมมากมาย เช่น ข้าวราดแกงเจ หูเตี๋ยวเจ บุ๋นเว้เจ เฝอเจ บุ๋นเรียวเจ บะหมี่ผัดเจ ข้าวผัดเจ เหมาะสำหรับมื้อเที่ยงรวดเร็วหรือมื้อเย็นเบาๆ ทุกจานปรุงรสอ่อนๆ ใส่ใจสมดุลทางโภชนาการและดีต่อสุขภาพ บรรยากาศเรียบง่าย อบอุ่น เหมาะทั้งสำหรับคนทานเจเป็นประจำและผู้ที่อยากเปลี่ยนมาทานมื้อเจที่ดีต่อสุขภาพและประหยัด', NULL, 1, NOW());

INSERT INTO "POIContents" ("POId", "Language", "TextContent", "AudioUrl", "ContentType", "CreatedAt")
VALUES (32, 'fr', 'Le restaurant végétarien Hoa Sen est un établissement populaire et abordable, apprécié de nombreux clients pour son menu varié, ses saveurs accessibles et ses prix raisonnables. Il propose de nombreux plats végétariens populaires : repas complets, hủ tiếu, bún Huế, phở végétarien, bún riêu, nouilles sautées, riz sauté… parfaits pour un déjeuner rapide ou un dîner léger. Tous les plats sont préparés de manière légère, assaisonnés avec justesse, en veillant à l''équilibre nutritionnel et au bien-être. L''ambiance est simple et chaleureuse, convenant aussi bien aux végétariens réguliers qu''à ceux qui souhaitent varier avec un repas végétarien sain et économique.', NULL, 1, NOW());

COMMIT;
